using UnityEngine;
using System.Collections.Generic;

// PlayerStats.cs
public class PlayerStats : MonoBehaviour
{
    public int Health = 100;
    public int MaxHealth = 100;
    public int Currency = 0;

    // Optional: Event for UI updates or other systems to react to stat changes
    public event System.Action OnStatsChanged;

    public void ChangeHealth(int amount)
    {
        Health += amount;
        Health = Mathf.Clamp(Health, 0, MaxHealth);
        OnStatsChanged?.Invoke();
        Debug.Log($"Health changed by {amount}. Current Health: {Health}/{MaxHealth}");
    }

    public void ChangeCurrency(int amount)
    {
        Currency += amount;
        if (Currency < 0) Currency = 0; // Prevent negative currency
        OnStatsChanged?.Invoke();
        Debug.Log($"Currency changed by {amount}. Current Currency: {Currency}");
    }

    public void ChangeMaxHealth(int amount)
    {
        MaxHealth += amount;
        if (MaxHealth < 1) MaxHealth = 1; // Ensure MaxHealth is at least 1
        // When max health increases, often current health should also increase by the same amount, up to the new max.
        ChangeHealth(amount);
        OnStatsChanged?.Invoke();
        Debug.Log($"Max Health changed by {amount}. New Max Health: {MaxHealth}");
    }
}

